// Inicializar config
$input.first().json = {
  config: {
    KPSULA_HOST: "https://pokepok.kpsula.app",
    KPSULA_API_KEY: "TU_API_KEY_AQUI",
    KPSULA_WEBHOOK_SECRET: "TU_SECRET_AQUI",
    TELEGRAM_BOT_TOKEN: "TU_BOT_TOKEN_AQUI"
  }
};
return $input.first();

// Validar firma HMAC-SHA256
const crypto = require('crypto');
const body = JSON.stringify($input.first().json.body);
const signature = $input.first().json.headers['x-kpsula-signature'];
const secret = $input.first().json.config.KPSULA_WEBHOOK_SECRET;

if (!signature) {
  throw new Error('Missing X-Kpsula-Signature header');
}

const expectedSig = crypto.createHmac('sha256', secret).update(body).digest('hex');
if (signature !== expectedSig) {
  throw new Error('Invalid signature');
}

return {
  ...Object.fromEntries(Object.entries($input.first().json).map(([k, v]) => [k, v])),
  isValid: true
};

